  1	import * as React from 'react';
  2	import { useCustomTranslation } from '@odf/shared';
  3	import {
  4	  Toolbar,
  5	  ToolbarContent,
  6	  ToolbarItem,
  7	  Button,
  8	  SearchInput,
  9	  Select,
 10	  SelectList,
 11	  SelectOption,
 12	  MenuToggle,
 13	  MenuToggleElement,
 14	  DatePicker,
 15	  TimePicker,
 16	  Tooltip,
 17	} from '@patternfly/react-core';
 18	import { getTodayDate } from './utils';
 19	import './health-overview-filter-toolbox.scss';
 20	
 21	type DateTimePickerProps = {
 22	  dateValue?: string;
 23	  timeValue?: string;
 24	  onDateChange: (value: string) => void;
 25	  onTimeChange: (value: string) => void;
 26	  dateAriaLabel: string;
 27	  timeAriaLabel: string;
 28	  datePlaceholder?: string;
 29	  timePlaceholder?: string;
 30	  tooltip?: string;
 31	};
 32	
 33	const DateTimePicker: React.FC<DateTimePickerProps> = ({
 34	  dateValue = '',
 35	  timeValue = '',
 36	  onDateChange,
 37	  onTimeChange,
 38	  dateAriaLabel,
 39	  timeAriaLabel,
 40	  datePlaceholder = 'YYYY-MM-DD',
 41	  timePlaceholder = 'hh:mm AM/PM',
 42	  tooltip = '',
 43	}) => {
 44	  const handleDateChange = (
 45	    _event: React.FormEvent<HTMLInputElement>,
 46	    date: string
 47	  ) => {
 48	    // If date is set but no time is set, automatically set time to 12:00 AM
 49	    if (date && !timeValue) {
 50	      onTimeChange('12:00 AM');
 51	    }
 52	    onDateChange(date);
 53	  };
 54	
 55	  const handleTimeChange = (
 56	    _event: React.FormEvent<HTMLInputElement>,
 57	    time: string
 58	  ) => {
 59	    // If time is set but no date is set, automatically set today's date
 60	    if (time && !dateValue) {
 61	      onDateChange(getTodayDate());
 62	    }
 63	    onTimeChange(time);
 64	  };
 65	
 66	  const dateTimeContent = (
 67	    <div
 68	      className="health-overview-filter-toolbox__datetime-group"
 69	      style={{ display: 'inline-flex' }}
 70	    >
 71	      <ToolbarItem className="health-overview-filter-toolbox__datetime-item">
 72	        <DatePicker
 73	          key={`date-${dateValue}`}
 74	          value={dateValue}
 75	          onChange={handleDateChange}
 76	          aria-label={dateAriaLabel}
 77	          placeholder={datePlaceholder}
 78	        />
 79	      </ToolbarItem>
 80	      <ToolbarItem className="health-overview-filter-toolbox__datetime-item">
 81	        <TimePicker
 82	          key={`time-${timeValue}`}
 83	          time={timeValue}
 84	          onChange={handleTimeChange}
 85	          aria-label={timeAriaLabel}
 86	          placeholder={timePlaceholder}
 87	        />
 88	      </ToolbarItem>
 89	    </div>
 90	  );
 91	
 92	  return tooltip ? (
 93	    <Tooltip content={tooltip}>{dateTimeContent}</Tooltip>
 94	  ) : (
 95	    dateTimeContent
 96	  );
 97	};
 98	
 99	export type HealthOverviewFilterToolboxProps = {
100	  checkTypeFilter?: string;
101	  onCheckTypeFilterChange: (value: string) => void;
102	  startDate?: string;
103	  onStartDateChange: (value: string) => void;
104	  startTime?: string;
105	  onStartTimeChange: (value: string) => void;
106	  endDate?: string;
107	  onEndDateChange: (value: string) => void;
108	  endTime?: string;
109	  onEndTimeChange: (value: string) => void;
110	  searchValue?: string;
111	  onSearchChange: (value: string) => void;
112	  onSilenceClick: () => void;
113	  isSilenceEnabled?: boolean;
114	};
115	
116	export const HealthOverviewFilterToolbox: React.FC<
117	  HealthOverviewFilterToolboxProps
118	> = ({
119	  checkTypeFilter = '',
120	  onCheckTypeFilterChange,
121	  startDate = '',
122	  onStartDateChange,
123	  startTime = '',
124	  onStartTimeChange,
125	  endDate = '',
126	  onEndDateChange,
127	  endTime = '',
128	  onEndTimeChange,
129	  searchValue = '',
130	  onSearchChange,
131	  onSilenceClick,
132	  isSilenceEnabled = false,
133	}) => {
134	  const { t } = useCustomTranslation();
135	  const [isCheckTypeOpen, setIsCheckTypeOpen] = React.useState(false);
136	
137	  const checkTypeOptions = [
138	    { value: 'all', label: t('All checks') },
139	    { value: 'critical', label: t('Critical') },
140	    { value: 'moderate', label: t('Moderate') },
141	    { value: 'minor', label: t('Minor') },
142	  ];
143	
144	  const onSelect = React.useCallback(
145	    (_event: React.MouseEvent | React.ChangeEvent, selection: string) => {
146	      onCheckTypeFilterChange(selection);
147	      setIsCheckTypeOpen(false);
148	    },
149	    [onCheckTypeFilterChange]
150	  );
151	
152	  const toggle = (toggleRef: React.Ref<MenuToggleElement>) => (
153	    <MenuToggle
154	      ref={toggleRef}
155	      onClick={() => setIsCheckTypeOpen((prev) => !prev)}
156	      isExpanded={isCheckTypeOpen}
157	      className="health-overview-filter-toolbox__check-type-toggle"
158	    >
159	      {checkTypeOptions.find((opt) => opt.value === checkTypeFilter)?.label ||
160	        t('All checks')}
161	    </MenuToggle>
162	  );
163	
164	  const handleClearAllFilters = React.useCallback(() => {
165	    onCheckTypeFilterChange('all');
166	    onStartDateChange('');
167	    onStartTimeChange('');
168	    onEndDateChange('');
169	    onEndTimeChange('');
170	    onSearchChange('');
171	  }, [
172	    onCheckTypeFilterChange,
173	    onStartDateChange,
174	    onStartTimeChange,
175	    onEndDateChange,
176	    onEndTimeChange,
177	    onSearchChange,
178	  ]);
179	
180	  return (
181	    <Toolbar className="health-overview-filter-toolbox">
182	      <ToolbarContent>
183	        <div className="health-overview-filter-toolbox__severity-wrapper">
184	          <Tooltip content={t('Severity')}>
185	            <ToolbarItem className="health-overview-filter-toolbox__item">
186	              <Select
187	                isOpen={isCheckTypeOpen}
188	                selected={checkTypeFilter || 'all'}
189	                onSelect={onSelect}
190	                onOpenChange={(open) => setIsCheckTypeOpen(open)}
191	                toggle={toggle}
192	                shouldFocusFirstItemOnOpen
193	                shouldFocusToggleOnSelect
194	              >
195	                <SelectList>
196	                  {checkTypeOptions.map((option) => (
197	                    <SelectOption key={option.value} value={option.value}>
198	                      {option.label}
199	                    </SelectOption>
200	                  ))}
201	                </SelectList>
202	              </Select>
203	            </ToolbarItem>
204	          </Tooltip>
205	          <Button
206	            variant="link"
207	            onClick={handleClearAllFilters}
208	            className="health-overview-filter-toolbox__clear-filters"
209	          >
210	            {t('Clear all filters')}
211	          </Button>
212	        </div>
213	
214	        <DateTimePicker
215	          dateValue={startDate}
216	          timeValue={startTime}
217	          onDateChange={onStartDateChange}
218	          onTimeChange={onStartTimeChange}
219	          dateAriaLabel={t('Start date')}
220	          timeAriaLabel={t('Start time')}
221	          tooltip={t('Start date and time filter')}
222	        />
223	
224	        <DateTimePicker
225	          dateValue={endDate}
226	          timeValue={endTime}
227	          onDateChange={onEndDateChange}
228	          onTimeChange={onEndTimeChange}
229	          dateAriaLabel={t('End date')}
230	          timeAriaLabel={t('End time')}
231	          tooltip={t('End date and time filter')}
232	        />
233	
234	        <ToolbarItem className="health-overview-filter-toolbox__item health-overview-filter-toolbox__search">
235	          <SearchInput
236	            placeholder={t('Find by name or details')}
237	            value={searchValue}
238	            onChange={(_event, value) => onSearchChange(value)}
239	            onClear={() => onSearchChange('')}
240	            aria-label={t('Find by name or details')}
241	          />
242	        </ToolbarItem>
243	
244	        <ToolbarItem className="health-overview-filter-toolbox__item">
245	          <Button
246	            variant="primary"
247	            onClick={onSilenceClick}
248	            isDisabled={!isSilenceEnabled}
249	          >
250	            {t('Silence')}
251	          </Button>
252	        </ToolbarItem>
253	      </ToolbarContent>
254	    </Toolbar>
255	  );
256	};

